using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class EchoTool
{
    [McpServerTool, Description("Echoes the input message back to the caller.")]
    public static string Echo([Description("The message to echo")] string message)
    {
        return $"Echo: {message}";
    }

    [McpServerTool, Description("Returns the current server time in UTC.")]
    public static string GetServerTime()
    {
        return DateTime.UtcNow.ToString("o");
    }
}

using ModelContextProtocol.Server;
using System.Text.Json;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["appName"] = "McpHttpServer",
        ["version"] = "1.0.0",
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["notifications"] = true,
            ["betaFeatures"] = false,
        },
        ["maxRetries"] = 3,
    };

    [McpServerResource(
        Name = "config://app",
        Uri = "config://app",
        Description = "Returns the current application configuration as JSON.",
        MimeType = "application/json")]
    public static string GetAppConfig()
    {
        return JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });
    }
}

